class Solution {
public:
    int maxPower(vector<vector<int>>& sensors) {
        sort(sensors.begin(), sensors.end());
        int maxPower = 0;
        for (int i = 0; i < sensors.size(); i++) {
            maxPower += sensors[i][0];
            if (sensors[i][0] <= sensors[i-1][0]) {
                break;
            }
        }
        return maxPower;
    }
};

